import * as fs from "fs";
import * as path from "path";

export interface QueryResult {
  file: string;
  line: number;
  column: number;
  text: string;
  kind: "definition" | "reference" | "call";
}

export interface QueryOptions {
  cwd?: string;
  includePattern?: string;
  excludeDirs?: string[];
}

const DEFAULT_EXCLUDE = [
  "node_modules",
  ".git",
  "dist",
  "out",
  ".next",
  ".nuxt",
  "build",
  "coverage",
];

function rgAvailable(): boolean {
  try {
    execSync("rg --version", { stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

function searchWithGrep(
  pattern: string,
  cwd: string,
  extraArgs: string[] = []
): string {
  try {
    const cmd = `rg --no-heading -n -S ${extraArgs.join(" ")} ${JSON.stringify(pattern)}`;
    return execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
  } catch (e: any) {
    if (e.status === 1) return "";
    throw e;
  }
}

function searchWithGrepFallback(
  pattern: string,
  cwd: string,
  extraArgs: string[] = []
): string {
  try {
    const excludeArgs = DEFAULT_EXCLUDE.map(
      (d) => `--exclude-dir=${JSON.stringify(d)}`
    );
    const cmd = `grep -rn -E ${excludeArgs.join(" ")} ${extraArgs.join(" ")} ${JSON.stringify(pattern)} .`;
    return execSync(cmd, { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 });
  } catch {
    return "";
  }
}

function searchFiles(
  pattern: string,
  cwd: string,
  extraArgs: string[] = []
): string {
  if (rgAvailable()) {
    return searchWithGrep(pattern, cwd, extraArgs);
  }
  return searchWithGrepFallback(pattern, cwd, extraArgs);
}

function parseGrepOutput(output: string): QueryResult[] {
  if (!output.trim()) return [];
  return output
    .trim()
    .split("\n")
    .map((line) => {
      const match = line.match(/^([^:]+):(\d+):(.*)$/);
      if (!match) return null;
      return {
        file: match[1],
        line: parseInt(match[2], 10),
        column: 0,
        text: match[3].trim(),
        kind: "reference" as const,
      };
    })
    .filter((r): r is QueryResult => r !== null);
}

function findProjectFiles(cwd: string): string[] {
  const pattern = rgAvailable() ? "-g '!node_modules' -g '!.git' -g '!dist' -g '!out' -g '!build'" : "";
  const exts = [".ts", ".tsx", ".js", ".jsx", ".mjs", ".cjs"];
  let allFiles: string[] = [];
  for (const ext of exts) {
    try {
      const result = execSync(
        `find . -name '*${ext}' -not -path '*/node_modules/*' -not -path '*/.git/*' -not -path '*/dist/*' -not -path '*/out/*' -not -path '*/build/*' -not -path '*/.next/*'`,
        { cwd, encoding: "utf-8", maxBuffer: 10 * 1024 * 1024 }
      );
      allFiles.push(
        ...result.trim().split("\n").filter(Boolean).map((f) => f.slice(2))
      );
    } catch {
      // ignore
    }
  }
  return allFiles;
}

function isDefinitionLine(text: string, symbol: string): boolean {
  const patterns = [
    new RegExp(`^(export\\s+)?(default\\s+)?(async\\s+)?function\\s+${escapeRegex(symbol)}\\s*\\(`),
    new RegExp(`^(export\\s+)?(const|let|var)\\s+${escapeRegex(symbol)}\\s*=`),
    new RegExp(`^(export\\s+)?(const|let|var)\\s+${escapeRegex(symbol)}\\s*:`),
    new RegExp(`^(export\\s+)?class\\s+${escapeRegex(symbol)}\\b`),
    new RegExp(`^(export\\s+)?interface\\s+${escapeRegex(symbol)}\\b`),
    new RegExp(`^(export\\s+)?type\\s+${escapeRegex(symbol)}\\s*=`),
    new RegExp(`^(export\\s+)?enum\\s+${escapeRegex(symbol)}\\s*\\{`),
    new RegExp(`^(export\\s+)?namespace\\s+${escapeRegex(symbol)}\\s*\\{`),
    new RegExp(`^\\s*(get|set)\\s+${escapeRegex(symbol)}\\s*\\(`),
    new RegExp(`^\\s*${escapeRegex(symbol)}\\s*\\(.*\\)\\s*\\{`),
  ];
  return patterns.some((p) => p.test(text));
}

function isCallSite(text: string, symbol: string): boolean {
  const callPatterns = [
    new RegExp(`${escapeRegex(symbol)}\\s*\\(`),
    new RegExp(`await\\s+${escapeRegex(symbol)}\\s*\\(`),
    new RegExp(`${escapeRegex(symbol)}\\.<`),
    new RegExp(`new\\s+${escapeRegex(symbol)}\\s*\\(`),
    new RegExp(`${escapeRegex(symbol)}\\s*\\?\\.`),
  ];
  return callPatterns.some((p) => p.test(text));
}

function escapeRegex(s: string): string {
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function resolveCwd(options: QueryOptions): string {
  if (options.cwd) return path.resolve(options.cwd);
  try {
    return execSync("git rev-parse --show-toplevel", {
      encoding: "utf-8",
    }).trim();
  } catch {
    return process.cwd();
  }
}

export function findDefinition(
  symbol: string,
  options: QueryOptions = {}
): QueryResult[] {
  const cwd = resolveCwd(options);
  const output = searchFiles(`\\b${escapeRegex(symbol)}\\b`, cwd, [
    ...DEFAULT_EXCLUDE.flatMap((d) => ["-g", `!${d}`]),
    "-g",
    "*.{ts,tsx,js,jsx,mjs,cjs}",
  ]);
  const results = parseGrepOutput(output);
  return results
    .filter((r) => isDefinitionLine(r.text, symbol))
    .map((r) => ({ ...r, kind: "definition" as const }));
}

export function findReferences(
  symbol: string,
  options: QueryOptions = {}
): QueryResult[] {
  const cwd = resolveCwd(options);
  const output = searchFiles(`\\b${escapeRegex(symbol)}\\b`, cwd, [
    ...DEFAULT_EXCLUDE.flatMap((d) => ["-g", `!${d}`]),
    "-g",
    "*.{ts,tsx,js,jsx,mjs,cjs}",
  ]);
  const results = parseGrepOutput(output);
  return results.map((r) => {
    if (isDefinitionLine(r.text, symbol)) {
      return { ...r, kind: "definition" as const };
    }
    return { ...r, kind: "reference" as const };
  });
}

export function findCallers(
  symbol: string,
  options: QueryOptions = {}
): QueryResult[] {
  const cwd = resolveCwd(options);
  const definitions = findDefinition(symbol, options);
  const defFiles = new Set(definitions.map((d) => d.file));
  const output = searchFiles(`\\b${escapeRegex(symbol)}\\b`, cwd, [
    ...DEFAULT_EXCLUDE.flatMap((d) => ["-g", `!${d}`]),
    "-g",
    "*.{ts,tsx,js,jsx,mjs,cjs}",
  ]);
  const results = parseGrepOutput(output);
  return results
    .filter((r) => isCallSite(r.text, symbol) && !defFiles.has(r.file))
    .map((r) => ({ ...r, kind: "call" as const }));
}
