   459→  start(): void {
   460→    // CLI → IM: route events from IPC to Discord threads
   461→    this.registry.on('session:event', (session, msg) => {
   462→      this.routeToIM(session, msg).catch(err => {
   463→        console.error(`[router] Error routing to IM:`, err);
   464→      });
   465→    });
   466→
   467→    // CLI → IM: permission requests
   468→    this.ipc.on('permission_request', (msg) => {
   469→      this.handlePermissionRequest(msg).catch(err => {
   470→        console.error(`[router] Error handling permission request:`, err);
   471→      });
   472→    });
   473→
   474→    // IM → CLI: messages from Discord threads
   475→    this.discord.onInboundMessage = (session, text, userId) => {
   476→      this.routeFromIM(session, text, userId).catch(err => {
   477→        console.error(`[router] Error routing from IM:`, err);
   478→      });
   479→    };
   480→
   481→    // IM → CLI: permission decisions from Discord buttons
   482→    this.discord.onPermissionDecision = (permissionId, decision) => {
   483→      this.handlePermissionDecision(permissionId, decision);
   484→    };
   485→
   486→    // Hub channel commands (delegated from Discord adapter)
   487→    this.discord.onHubCommand = (command, args, ctx) => {
   488→      this.handleHubCommand(command, args, ctx).catch(err => {
   489→        console.error('[router] Error handling hub command:', err);
   490→      });
   491→    };
   492→
   493→    // Claude transcript watcher: forward assistant text on session register
   494→    // Skip SDK sessions — their output is already routed via stream events
   495→    this.registry.on('session:registered', (session) => {
   496→      if (session.agent !== 'codex' && session.source !== 'sdk') {
   497→        this.transcriptWatcher.startWatching(session.sessionId, session.cwd);
   498→      }
   499→    });
   500→    this.registry.on('session:ended', (session) => {
   501→      this.transcriptWatcher.stopWatching(session.sessionId);
   502→    });
   503→    this.transcriptWatcher.on('assistant:text', (sessionId, text) => {
   504→      this.handleAssistantText(sessionId, text).catch(err => {
   505→        console.error('[router] Error sending assistant text:', err);
   506→      });
   507→    });
   508→
   509→    // Codex auto-detection: discovers sessions from SQLite, no wrapper needed
   510→    if (this.codexWatcherEnabled) {
   511→      this.codexWatcher.start();
   512→      this.codexWatcher.on('session:new', (thread) => {
   513→        this.handleCodexSessionNew(thread).catch(err => {
   514→          console.error('[router] Error registering codex session:', err);
   515→        });
   516→      });
   517→      this.codexWatcher.on('session:ended', (threadId) => {
   518→        const sid = `codex-${threadId}`;
   519→        this.registry.handleUnregister({ type: 'unregister', sessionId: sid });
   520→      });
   521→      this.codexWatcher.on('assistant:text', (threadId, text) => {
   522→        this.handleAssistantText(`codex-${threadId}`, text).catch(err => {
   523→          console.error('[router] Error sending codex text:', err);
   524→        });
   525→      });
   526→      this.codexWatcher.on('tool:call', (threadId, name, args) => {
   527→        this.handleCodexToolCall(`codex-${threadId}`, name, args).catch(err => {
   528→          console.error('[router] Error sending codex tool call:', err);
   529→        });
   530→      });
   531→      this.codexWatcher.on('user:message', (threadId, text) => {
   532→        this.handleCodexUserMessage(`codex-${threadId}`, text).catch(err => {
   533→          console.error('[router] Error sending codex user message:', err);
   534→        });
   535→      });
   536→    } else {
   537→      console.log('[router] Codex watcher disabled by AGENT_IM_DISABLE_CODEX_WATCHER=1');
