   799→  private async handlePermissionRequest(msg: PermissionRequestMsg): Promise<void> {
   800→    const session = this.registry.getSession(msg.sessionId);
   801→    if (!session?.threadId) {
   802→      console.warn(`[router] Permission ${msg.permissionId.slice(0, 8)} allowed locally: no IM thread bound for ${msg.sessionId.slice(0, 8)}`);
   803→      this.ipc.resolvePermission(msg.permissionId, 'allow', 'No IM thread bound; falling back to local approval');
   804→      return;
   805→    }
   806→
   807→    // Store pending permission
   808→    this.store.setPendingPermission({
   809→      permissionId: msg.permissionId,
   810→      sessionId: msg.sessionId,
   811→      toolName: msg.toolName,
   812→      toolInput: msg.toolInput,
   813→      createdAt: new Date().toISOString(),
   814→    });
   815→
   816→    // Send buttons to Discord thread
   817→    const discordMsgId = await this.discord.sendPermissionButtons(
   818→      session.threadId,
   819→      msg.permissionId,
   820→      msg.toolName,
   821→      msg.toolInput,
   822→    );
   823→
   824→    if (!discordMsgId) {
   825→      this.store.deletePendingPermission(msg.permissionId);
   826→      console.warn(`[router] Permission ${msg.permissionId.slice(0, 8)} allowed locally: failed to deliver IM approval request`);
   827→      this.ipc.resolvePermission(msg.permissionId, 'allow', 'IM approval delivery failed; falling back to local approval');
   828→      return;
   829→    }
   830→
   831→    const perm = this.store.getPendingPermission(msg.permissionId);
   832→    if (perm) {
   833→      perm.discordMessageId = discordMsgId;
   834→      this.store.setPendingPermission(perm);
   835→    }
   836→  }
