   856→  // ── IM → CLI ──
   857→
   858→  private async routeFromIM(session: CLISession, text: string, _userId: string): Promise<void> {
   859→    const trimmed = this.normalizeInboundText(text);
   860→
   861→    // Thread-level commands
   862→    if (trimmed.startsWith('!') || trimmed.startsWith('/')) {
   863→      await this.handleThreadCommand(session, trimmed);
   864→      return;
   865→    }
   866→
   867→    const recoveryToken = this.extractRecoveryToken(trimmed);
   868→    if (recoveryToken) {
   869→      await this.handleRecoveryToken(session, recoveryToken);
   870→      return;
   871→    }
   872→
   873→    // Numeric permission shortcut
   874→    if (/^[123]$/.test(trimmed)) {
   875→      const pending = this.store.getPendingBySession(session.sessionId);
   876→      if (pending.length > 0) {
   877→        const latest = pending[pending.length - 1];
   878→        const decision = trimmed === '3' ? 'deny' : 'allow';
   879→        this.handlePermissionDecision(latest.permissionId, decision);
   880→        return;
   881→      }
   882→    }
   883→
   884→    // Codex auto-detected sessions are observe-only for now.
   885→    // Never try to resume them via Claude SDK — their session IDs are not Claude UUIDs.
   886→    if (session.agent === 'codex') {
   887→      if (session.threadId) {
   888→        await this.discord.sendToThread(
   889→          session.threadId,
   890→          '⚠️ 这是 `observe-only` 的 Codex session，线程内回复暂时不会注回本地终端。可用 `!help` / `!info` / `!filter`，或直接回到本地 Codex 继续。',
   891→        );
   892→      }
   893→      return;
   894→    }
   895→
   896→    // Phase 2: Route message via Agent SDK
   897→    if (!this.sdkManager) {
   898→      console.log(`[router] IM → CLI [${session.sessionId.slice(0, 8)}]: ${trimmed} (SDK not configured)`);
   899→      if (session.threadId) {
   900→        await this.discord.sendToThread(session.threadId, '⚠️ 当前未配置 SDK session manager。');
   901→      }
   902→      return;
   903→    }
   904→
   905→    // Check if SDK is running for this session
   906→    if (this.sdkManager.isRunning(session.sessionId)) {
   907→      if (session.threadId) {
   908→        await this.discord.sendToThread(session.threadId, '⏳ 当前 SDK turn 仍在执行，先等它结束。');
   909→      }
   910→      return;
   911→    }
   912→
   913→    // CC is actively running locally — can't resume (would conflict)
   914→    if (session.source === 'hook' && session.status === 'active') {
   915→      if (session.threadId) {
   916→        await this.discord.sendToThread(session.threadId, '⏳ 本地 Claude Code 还在 active。等它进入 idle 后再试。');
   917→      }
   918→      return;
   919→    }
   920→
   921→    // Show typing indicator while LLM is working
   922→    if (session.threadId) {
   923→      this.discord.sendTyping(session.threadId).catch(() => {});
   924→    }
   925→
   926→    // Always try to resume first — shared conversation history with CC
   927→    // Save prompt for retry if resume fails (signature error detected in stream)
   928→    this.sdkLastPrompt.set(session.sessionId, trimmed);
   929→    try {
   930→      const sid = await this.sdkManager.startSession(trimmed, {
   931→        resume: session.sessionId,
   932→        cwd: session.cwd,
   933→        model: session.model,
   934→        provider: session.provider,
   935→        ccBaseUrl: session.baseUrl,
   936→        ccAuthToken: session.authToken,
   937→      });
   938→      session.source = 'sdk';
   939→      session.status = 'active';
   940→      session.lastActivityAt = new Date().toISOString();
   941→      this.store.setSession(session);
   942→      this.transcriptWatcher.stopWatching(session.sessionId);
   943→      console.log(`[router] IM → SDK resume [${sid.slice(0, 8)}]: ${trimmed.slice(0, 80)}`);
   944→      return;
   945→    } catch (err) {
   946→      const errMsg = err instanceof Error ? err.message : String(err);
   947→      console.warn(`[router] Resume failed: ${errMsg}`);
   948→
   949→      // Signature/thinking block error → fallback to fresh, warn user
   950→      if (errMsg.includes('signature') || errMsg.includes('thinking') || errMsg.includes('400')) {
   951→        try {
   952→          if (session.threadId) {
   953→            await this.discord.sendToThread(session.threadId, `⚠️ 无法接入原 session（API key 不同）。本次回复不会出现在 CC 中。`);
   954→          }
   955→          const sid = await this.sdkManager.startSession(trimmed, {
   956→            cwd: session.cwd,
   957→            model: session.model,
   958→            provider: session.provider,
   959→          });
   960→          session.status = 'active';
   961→          session.lastActivityAt = new Date().toISOString();
