  1260→  private normalizeInboundText(text: string): string {
  1261→    const trimmed = text.trim();
  1262→    if (!trimmed) return trimmed;
  1263→    if (trimmed.startsWith('！')) return `!${trimmed.slice(1)}`;
  1264→    if (trimmed.startsWith('／')) return `/${trimmed.slice(1)}`;
  1265→    return trimmed;
  1266→  }
