  1359→    if (latestPrompt) carryLines.push(`Latest user prompt: ${latestPrompt}`);
  1360→    if (recentFiles.length > 0) carryLines.push(`Recent files: ${recentFiles.join(', ')}`);
  1361→    carryLines.push(`Carry-forward note: ${mode.hint}`);
  1362→
  1363→    return [
  1364→      '**Distill**',
  1365→      '_MindKeeper 当前不可用，已回退到本地 session 摘要。_',
  1366→      '如果要在别处继续，把下面这段上下文贴过去即可。',
