  1389→      ];
  1390→      if (input.latestPrompt) {
  1391→        findings.push(`Latest user prompt: ${input.latestPrompt}`);
  1392→      }
  1393→      if (session.model) {
  1394→        findings.push(`Model: ${session.model}${session.provider ? ` [${session.provider}]` : ''}`);
  1395→      } else if (session.provider) {
  1396→        findings.push(`Provider: ${session.provider}`);
