  1467→  private shouldForward(eventType: string, level: FilterLevel, toolName?: string): boolean {
  1468→    if (ALWAYS_FORWARD.has(eventType)) return true;
  1469→    if (level === 'full') return true;
  1470→    if (level === 'summary') {
  1471→      if (SUMMARY_EVENTS.has(eventType)) return true;
  1472→      // For tool events, only show tools that make changes
  1473→      if ((eventType === 'tool_use' || eventType === 'tool_result') && toolName) {
  1474→        return SUMMARY_TOOLS.has(toolName);
  1475→      }
  1476→      return false;
  1477→    }
  1478→    if (level === 'compact') return COMPACT_EVENTS.has(eventType);
