  1516→
  1517→    // Rate limit: 5 min cooldown
  1518→    if (now - ctx.lastTitleUpdate < ContentRouter.TITLE_COOLDOWN_MS) return;
  1519→    // Need a user prompt for meaningful title context (don't waste the first update on tool-only events)
  1520→    if (!ctx.latestPrompt) return;
  1521→
  1522→    const newTitle = this.generateTitle(session);
  1523→    if (newTitle === ctx.currentTitle) return;
  1524→    const updated = await this.discord.updateThreadTitle(session.threadId, newTitle);
  1525→    if (!updated) return;
  1526→
  1527→    ctx.currentTitle = newTitle;
  1528→    ctx.lastTitleUpdate = now;
  1529→
  1530→    // Extract short task summary for hub card
  1531→    const sctx = this.sessionContext.get(session.sessionId);
  1532→    if (sctx?.latestPrompt) {
