  1543→  /** Update SDK session title from prompt or response text */
  1544→  private async updateSdkTitle(sessionId: string, responseText: string): Promise<void> {
  1545→    const session = this.registry.getSession(sessionId);
  1546→    if (!session?.threadId) return;
  1547→
  1548→    // Use prompt as title (user's intent), fallback to response first line
  1549→    const prompt = this.sdkLastPrompt.get(sessionId) || '';
  1550→    let summary = prompt.split('\n')[0].trim();
  1551→    summary = summary.replace(/^(please|help me|can you|I want to|I need to|请|帮我|帮忙)\s*/i, '');
  1552→
  1553→    if (!summary) {
  1554→      const lines = responseText.split('\n').map(l => l.trim()).filter(Boolean);
  1555→      for (const line of lines) {
  1556→        const cleaned = line.replace(/^#{1,4}\s*/, '').replace(/\*{1,2}/g, '').trim();
  1557→        if (cleaned.length >= 3) { summary = cleaned; break; }
  1558→      }
  1559→    }
  1560→
  1561→    if (!summary) return;
  1562→    summary = summary.length > 50 ? summary.slice(0, 47) + '...' : summary;
  1563→
  1564→    const shortId = session.sessionId.slice(0, 6);
  1565→    const title = `${session.project} / ${session.branch} — ${summary} [${shortId}]`;
  1566→    const truncated = title.length > 100 ? title.slice(0, 97) + '...' : title;
  1567→
  1568→    const updated = await this.discord.updateThreadTitle(session.threadId, truncated);
  1569→    if (!updated) return;
  1570→
  1571→    session.title = summary;
  1572→    this.store.setSession(session);
  1573→    this.registry.emit('session:active', session);
