  1643→  /**
  1644→   * Resolve a short name to a full cwd path.
  1645→   * Search chain: recent sessions → zoxide query.
  1646→   */
  1647→  private resolveCwdShortcut(name: string): string | null {
  1648→    const lower = name.toLowerCase();
  1649→
  1650→    // 1. Recent/active sessions
  1651→    for (const session of this.registry.listAll()) {
  1652→      const project = session.project.toLowerCase();
  1653→      if (project === lower || project.includes(lower)) {
  1654→        return session.cwd;
  1655→      }
  1656→    }
  1657→
  1658→    // 2. zoxide query (frecency-based, same as `z` command)
  1659→    try {
  1660→      const result = execSync(`zoxide query ${name}`, {
  1661→        encoding: 'utf-8',
  1662→        timeout: 2000,
  1663→        stdio: ['pipe', 'pipe', 'pipe'],
  1664→      }).trim();
  1665→      if (result && result.startsWith('/')) return result;
  1666→    } catch {
  1667→      // zoxide not installed or no match
  1668→    }
  1669→
  1670→    return null;
  1671→  }
